command:
printf 'dimensions:
  performance: {enabled: true}
  velocity: {enabled: true}
retention_days: 90
share: never
' > space/config.yaml && bash "$CLAUDE_PLUGIN_ROOT/space/validate-config.sh" --config space/config.yaml 2>err.txt; rc=$?; [ "$rc" -ne 0 ] && grep -q 'velocity' err.txt && echo blocked 1>&2
